/**
 * HoneyAI — Main Orchestrator
 * Starts all enabled protocol honeypots and the management API.
 *
 * Usage:
 *   node server.js           # Uses config.yaml
 *   pnpm run setup            # Interactive setup wizard
 */

'use strict';

// Load .env if present (generated by setup wizard)
const fs   = require('fs');
const path = require('path');
const envPath = path.join(__dirname, '.env');
if (fs.existsSync(envPath)) {
    require('fs').readFileSync(envPath, 'utf8').split('\n').forEach(line => {
        const [k, ...v] = line.split('=');
        if (k && v.length) {
            let val = v.join('=').trim();
            if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
                val = val.substring(1, val.length - 1);
            }
            process.env[k.trim()] = val;
        }
    });
}


const config   = require('./core/config');
const { logger } = require('./core/logger');
const { readLastLinesSync } = require('./core/fileReader');

